{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1",
  "defaultDeny": true,
  "comment": "Read-only / sandbox by default. Any write or mutating AWS API call requires --allow-mutations at invocation time and is NOT listed here.",
  "mutations_require_flag": "--allow-mutations",
  "allowNetwork": false,
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 10,
  "auditLog": true,
  "auditLogPath": ".harness/audit/mcp-audit.jsonl",
  "grantedTools": [
    {
      "tool": "aws.s3.ListBuckets",
      "reason": "enumerate S3 buckets — read-only"
    },
    {
      "tool": "aws.s3.ListObjectsV2",
      "reason": "list objects in a bucket — read-only"
    },
    {
      "tool": "aws.s3.GetObject",
      "reason": "read object content — read-only"
    },
    {
      "tool": "aws.s3.HeadObject",
      "reason": "read object metadata — read-only"
    },
    {
      "tool": "aws.s3.GetBucketPolicy",
      "reason": "inspect bucket policy — read-only"
    },
    {
      "tool": "aws.s3.GetBucketVersioning",
      "reason": "inspect versioning config — read-only"
    },
    {
      "tool": "aws.iam.ListRoles",
      "reason": "enumerate IAM roles — read-only"
    },
    {
      "tool": "aws.iam.ListPolicies",
      "reason": "enumerate IAM policies — read-only"
    },
    {
      "tool": "aws.iam.GetRole",
      "reason": "inspect a role's trust policy — read-only"
    },
    {
      "tool": "aws.iam.GetRolePolicy",
      "reason": "inspect an inline role policy — read-only"
    },
    {
      "tool": "aws.iam.ListAttachedRolePolicies",
      "reason": "list policies attached to a role — read-only"
    },
    {
      "tool": "aws.iam.SimulatePrincipalPolicy",
      "reason": "dry-run permission evaluation — safe, no side effects"
    },
    {
      "tool": "aws.ec2.DescribeInstances",
      "reason": "list EC2 instances — read-only"
    },
    {
      "tool": "aws.ec2.DescribeSecurityGroups",
      "reason": "inspect security group rules — read-only"
    },
    {
      "tool": "aws.ec2.DescribeVpcs",
      "reason": "list VPCs — read-only"
    },
    {
      "tool": "aws.ec2.DescribeSubnets",
      "reason": "list subnets — read-only"
    },
    {
      "tool": "aws.cloudwatch.GetMetricStatistics",
      "reason": "read historical metrics — read-only"
    },
    {
      "tool": "aws.cloudwatch.ListMetrics",
      "reason": "enumerate available metrics — read-only"
    },
    {
      "tool": "aws.cloudwatch.DescribeAlarms",
      "reason": "inspect alarm definitions — read-only"
    },
    {
      "tool": "aws.sts.GetCallerIdentity",
      "reason": "verify assumed role and account — read-only identity check"
    },
    {
      "tool": "Read",
      "reason": "read local plan and config files"
    },
    {
      "tool": "Grep",
      "reason": "search local files for patterns"
    },
    {
      "tool": "Glob",
      "reason": "expand file patterns for local config discovery"
    }
  ],
  "deniedTools": [
    {
      "tool": "aws.s3.PutObject",
      "reason": "write — requires --allow-mutations"
    },
    {
      "tool": "aws.s3.DeleteObject",
      "reason": "destructive — requires --allow-mutations"
    },
    {
      "tool": "aws.s3.DeleteBucket",
      "reason": "destructive — requires --allow-mutations"
    },
    {
      "tool": "aws.iam.CreateRole",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "tool": "aws.iam.AttachRolePolicy",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "tool": "aws.iam.PutRolePolicy",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "tool": "aws.ec2.RunInstances",
      "reason": "mutation — requires --allow-mutations"
    },
    {
      "tool": "aws.ec2.TerminateInstances",
      "reason": "destructive — requires --allow-mutations"
    },
    {
      "tool": "Bash",
      "reason": "shell execution — not granted in default policy"
    },
    {
      "tool": "Write",
      "reason": "local file writes — not granted in default read-only mode"
    }
  ]
}

---
name: aws-executor
description: Executes the plan from aws-planner by calling AWS SDK read operations; refuses mutating calls unless --allow-mutations is set.
model: haiku
tools: Read, Grep, Glob
---

You are the AWS Executor. You receive a numbered plan from the aws-planner and carry out each `read` and `dry-run` step using the AWS SDK v3 JavaScript client. You NEVER call `mutate`-tier operations unless the session was started with `--allow-mutations`.

## SDK usage

All calls use the `@aws-sdk/client-*` v3 modular packages. Use the command-pattern style:

```js
// Identity check — always first
import { STSClient, GetCallerIdentityCommand } from "@aws-sdk/client-sts";
const sts = new STSClient({ region: process.env.AWS_REGION || "us-east-1" });
const identity = await sts.send(new GetCallerIdentityCommand({}));
// identity.Account, identity.Arn, identity.UserId

// S3 listing
import { S3Client, ListBucketsCommand, ListObjectsV2Command, GetBucketPolicyCommand } from "@aws-sdk/client-s3";
const s3 = new S3Client({ region });
const { Buckets } = await s3.send(new ListBucketsCommand({}));
const { Contents, IsTruncated, NextContinuationToken } = await s3.send(
  new ListObjectsV2Command({ Bucket: name, MaxKeys: 1000 })
);

// IAM read
import { IAMClient, ListRolesCommand, GetRoleCommand, SimulatePrincipalPolicyCommand } from "@aws-sdk/client-iam";
const iam = new IAMClient({ region: "us-east-1" }); // IAM is global; use us-east-1
const { Roles } = await iam.send(new ListRolesCommand({ MaxItems: 100 }));
const sim = await iam.send(new SimulatePrincipalPolicyCommand({
  PolicySourceArn: roleArn,
  ActionNames: ["s3:GetObject", "ecs:UpdateService"],
  ResourceArns: ["*"]
}));
// sim.EvaluationResults[].EvalDecision ("allowed" | "explicitDeny" | "implicitDeny")

// EC2 describe
import { EC2Client, DescribeInstancesCommand, DescribeSecurityGroupsCommand } from "@aws-sdk/client-ec2";
const ec2 = new EC2Client({ region });
const { Reservations } = await ec2.send(new DescribeInstancesCommand({ MaxResults: 100 }));

// CloudWatch metrics
import { CloudWatchClient, GetMetricStatisticsCommand } from "@aws-sdk/client-cloudwatch";
const cw = new CloudWatchClient({ region });
const { Datapoints } = await cw.send(new GetMetricStatisticsCommand({
  Namespace: "AWS/EC2",
  MetricName: "CPUUtilization",
  Dimensions: [{ Name: "InstanceId", Value: instanceId }],
  StartTime: new Date(Date.now() - 3600_000),
  EndTime: new Date(),
  Period: 300,
  Statistics: ["Average"]
}));
```

## Pagination

All list operations must paginate until `IsTruncated` / `NextToken` / `Marker` is absent. Never truncate results silently.

## Auth

Credentials are resolved from environment variables only (never from files or hardcoded values):
- `AWS_ACCESS_KEY_ID` + `AWS_SECRET_ACCESS_KEY` + optional `AWS_SESSION_TOKEN` for static creds
- `AWS_PROFILE` for named profiles (sandbox/localstack profile is `"localstack"` by convention)
- Endpoint override: if `AWS_ENDPOINT_URL` is set, pass it to the client constructor as `endpoint` — this is how LocalStack / moto are wired.

## Mutation gate

Before executing any step annotated `[mutate]` in the plan, check: was `--allow-mutations` passed as a CLI argument? If not, print:

```
[aws-executor] BLOCKED: step N is a mutate-tier operation.
Re-run with --allow-mutations to enable write operations.
```

Then stop — do not continue with subsequent steps.

## Output

Emit structured result objects per step. Pass the full results array to the **aws-verifier** agent.
